    private fun initializeLogging() {
        // Plant multiple Timber trees for comprehensive logging
        Timber.plant(VerboseDebugTree())
        Timber.plant(FileLoggingTree(this))
        Timber.plant(CrashReportingTree())

        // Set up global uncaught exception handler
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            Timber.e(throwable, "UNCAUGHT EXCEPTION on thread: ${thread.name}")
            AppLogger.logException("UncaughtException", throwable, mapOf("thread" to thread.name))
            defaultHandler?.uncaughtException(thread, throwable)
        }

        Timber.v("=== Application Started ===")
        Timber.v("Device: ${Build.MANUFACTURER} ${Build.MODEL}")
        Timber.v("OS: Android ${Build.VERSION.RELEASE} (API ${Build.VERSION.SDK_INT})")
        Timber.v("App Version: ${packageManager.getPackageInfo(packageName, 0).versionName}")
    }
