class VerboseDebugTree : Timber.DebugTree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val timestamp = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US).format(Date())
        val threadName = Thread.currentThread().name
        val priorityChar = when (priority) {
            Log.VERBOSE -> "V"
            Log.DEBUG -> "D"
            Log.INFO -> "I"
            Log.WARN -> "W"
            Log.ERROR -> "E"
            Log.ASSERT -> "A"
            else -> "?"
        }
        val formattedMessage = "[$timestamp][$priorityChar][$threadName] $message"
        super.log(priority, tag, formattedMessage, t)
    }

    override fun createStackElementTag(element: StackTraceElement): String {
        return "(${element.fileName}:${element.lineNumber})#${element.methodName}"
    }
}

class FileLoggingTree(private val context: Context) : Timber.Tree() {

    private val executor = Executors.newSingleThreadExecutor()
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val fileDateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        executor.execute {
            try {
                val logDir = File(context.filesDir, "logs")
                if (!logDir.exists()) logDir.mkdirs()

                val logFile = File(logDir, "app_log_${fileDateFormat.format(Date())}.txt")
                val writer = FileWriter(logFile, true)

                val priorityStr = when (priority) {
                    Log.VERBOSE -> "VERBOSE"
                    Log.DEBUG -> "DEBUG"
                    Log.INFO -> "INFO"
                    Log.WARN -> "WARN"
                    Log.ERROR -> "ERROR"
                    Log.ASSERT -> "ASSERT"
                    else -> "UNKNOWN"
                }

                val timestamp = dateFormat.format(Date())
                writer.append("$timestamp | $priorityStr | $tag | $message\n")

                if (t != null) {
                    val sw = StringWriter()
                    t.printStackTrace(PrintWriter(sw))
                    writer.append("$timestamp | STACKTRACE | $sw\n")
                }

                writer.flush()
                writer.close()

                // Cleanup old logs (keep last 7 days)
                cleanupOldLogs(logDir)
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Failed to write log to file", e)
            }
        }
    }

    private fun cleanupOldLogs(logDir: File) {
        val sevenDaysAgo = System.currentTimeMillis() - (7 * 24 * 60 * 60 * 1000)
        logDir.listFiles()?.forEach { file ->
            if (file.lastModified() < sevenDaysAgo) {
                file.delete()
            }
        }
    }
}

class CrashReportingTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (priority == Log.ERROR || priority == Log.ASSERT) {
            // In production, this would send to a crash reporting service
            // e.g., Firebase Crashlytics, Sentry, etc.
            CrashReportBuffer.addReport(
                CrashReport(
                    timestamp = System.currentTimeMillis(),
                    priority = priority,
                    tag = tag,
                    message = message,
                    throwable = t
                )
            )
        }
    }
}

data class CrashReport(
    val timestamp: Long,
    val priority: Int,
    val tag: String?,
    val message: String,
    val throwable: Throwable?
)

object CrashReportBuffer {
    private val reports = ConcurrentLinkedQueue<CrashReport>()
    private const val MAX_REPORTS = 100

    fun addReport(report: CrashReport) {
        reports.add(report)
        while (reports.size > MAX_REPORTS) {
            reports.poll()
        }
    }

    fun getReports(): List<CrashReport> = reports.toList()
    fun clear() = reports.clear()
}

