    fun logApiResponse(
        requestId: String,
        statusCode: Int,
        url: String,
        headers: Map<String, String> = emptyMap(),
        body: String? = null,
        durationMs: Long? = null,
        method: String = ""
    ) {
        val statusEmoji = when {
            statusCode in 200..299 -> "✅"
            statusCode in 300..399 -> "↗️"
            statusCode in 400..499 -> "⚠️"
            statusCode >= 500 -> "❌"
            else -> "❓"
        }

        val logLevel = when {
            statusCode in 200..299 -> Log.VERBOSE
            statusCode in 300..399 -> Log.INFO
            statusCode in 400..499 -> Log.WARN
            else -> Log.ERROR
        }

        val logFn: (String) -> Unit = when (logLevel) {
            Log.VERBOSE -> { msg -> Timber.v(msg) }
            Log.INFO -> { msg -> Timber.i(msg) }
            Log.WARN -> { msg -> Timber.w(msg) }
            Log.ERROR -> { msg -> Timber.e(msg) }
            else -> { msg -> Timber.v(msg) }
        }

        logFn("╔══════════════════════════════════════════════════")
        logFn("║ 🌐 API RESPONSE $statusEmoji")
        logFn("║ Request ID: $requestId")
        logFn("║ Session: $sessionId")
        logFn("║ Timestamp: ${dateFormat.format(Date())}")
        logFn("║ Status Code: $statusCode")
        logFn("║ URL: $url")
        if (method.isNotEmpty()) logFn("║ Method: $method")
        if (durationMs != null) {
            logFn("║ Duration: ${durationMs}ms")
            if (durationMs > 5000) {
                Timber.w("║ ⚠️ SLOW API CALL DETECTED (>${durationMs}ms)")
            }
        }
        if (headers.isNotEmpty()) {
            logFn("║ Response Headers:")
            headers.forEach { (key, value) ->
                logFn("║   $key: $value")
            }
        }
        if (body != null) {
            logFn("║ Response Body:")
            // Truncate very large bodies but log the size
            val maxBodyLength = 5000
            if (body.length > maxBodyLength) {
                body.take(maxBodyLength).lines().forEach { line ->
                    logFn("║   $line")
                }
                logFn("║   ... [TRUNCATED - Total size: ${body.length} bytes]")
            } else {
                body.lines().forEach { line ->
                    logFn("║   $line")
                }
            }
            logFn("║ Body Size: ${body.length} bytes")
        }
        logFn("╚══════════════════════════════════════════════════")
    }

