    fun logException(
        context: String,
        throwable: Throwable,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        Timber.e("╔══════════════════════════════════════════════════")
        Timber.e("║ 💥 EXCEPTION")
        Timber.e("║ Session: $sessionId")
        Timber.e("║ Timestamp: ${dateFormat.format(Date())}")
        Timber.e("║ Context: $context")
        Timber.e("║ Exception Type: ${throwable::class.qualifiedName}")
        Timber.e("║ Message: ${throwable.message}")
        if (metadata.isNotEmpty()) {
            Timber.e("║ Metadata:")
            metadata.forEach { (key, value) ->
                Timber.e("║   $key: $value")
            }
        }
        Timber.e("║ ── Full Stack Trace ──")
        val sw = StringWriter()
        throwable.printStackTrace(PrintWriter(sw))
        sw.toString().lines().forEach { line ->
            Timber.e("║   $line")
        }

        // Log the full cause chain
        var cause = throwable.cause
        var depth = 1
        while (cause != null) {
            Timber.e("║ ── Cause #$depth ──")
            Timber.e("║   Type: ${cause::class.qualifiedName}")
            Timber.e("║   Message: ${cause.message}")
            val causeSw = StringWriter()
            cause.printStackTrace(PrintWriter(causeSw))
            causeSw.toString().lines().take(10).forEach { line ->
                Timber.e("║     $line")
            }
            cause = cause.cause
            depth++
        }
        Timber.e("╚══════════════════════════════════════════════════")
    }

