    // --------------------------------------------------------
    // Helpers
    // --------------------------------------------------------
    private fun sanitizeHeaderValue(key: String, value: String): String {
        val sensitiveHeaders = listOf("authorization", "cookie", "set-cookie", "x-api-key", "api-key")
        return if (key.lowercase() in sensitiveHeaders) {
            if (value.length > 10) {
                "${value.take(6)}...${value.takeLast(4)} [REDACTED]"
            } else {
                "[REDACTED]"
            }
        } else {
            value
        }
    }
}

// ============================================================
// OkHttp Interceptor for comprehensive API logging
// ============================================================
class ComprehensiveLoggingInterceptor : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val requestId = UUID.randomUUID().toString().take(8)
        val startTime = System.currentTimeMillis()

        // Log the request
        logRequest(request, requestId)

        return try {
            val response = chain.proceed(request)
            val duration = System.currentTimeMillis() - startTime

            // Log the response
            logResponse(response, request, requestId, duration)

            response
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            AppLogger.logApiError(
                requestId = requestId,
                url = request.url.toString(),
                method = request.method,
                error = e,
                durationMs = duration
            )
            throw e
        }
    }

    private fun logRequest(request: Request, requestId: String) {
        val headers = mutableMapOf<String, String>()
        request.headers.forEach { (name, value) ->
            headers[name] = value
        }

        val body = request.body?.let { requestBody ->
            try {
                val buffer = Buffer()
                requestBody.writeTo(buffer)
                buffer.readUtf8()
            } catch (e: Exception) {
                "[Could not read body: ${e.message}]"
            }
        }

        val queryParams = mutableMapOf<String, String>()
        val url = request.url
        url.queryParameterNames.forEach { name ->
            url.queryParameter(name)?.let { value ->
                queryParams[name] = value
            }
        }

        AppLogger.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = headers,
            body = body,
            queryParams = queryParams,
            requestId = requestId
        )
    }

    private fun logResponse(response: Response, request: Request, requestId: String, duration: Long) {
        val headers = mutableMapOf<String, String>()
        response.headers.forEach { (name, value) ->
            headers[name] = value
        }

        val body = response.peekBody(Long.MAX_VALUE).string()

        AppLogger.logApiResponse(
            requestId = requestId,
            statusCode = response.code,
            url = request.url.toString(),
            headers = headers,
            body = body,
            durationMs = duration,
            method = request.method
        )
    }
}

// ============================================================
// Database Logger Helper
// ============================================================
class DatabaseLogger {

    companion object {
        fun <T> logQuery(
            query: String,
            parameters: Map<String, Any?> = emptyMap(),
            tableName: String? = null,
            operation: String = "SELECT",
            block: () -> T
        ): T {
            val startTime = System.currentTimeMillis()
            return try {
                val result = block()
                val duration = System.currentTimeMillis() - startTime

                val resultCount = when (result) {
                    is List<*> -> result.size
                    is Collection<*> -> result.size
                    is Array<*> -> result.size
                    else -> null
                }

                AppLogger.logDatabaseQuery(
                    query = query,
                    parameters = parameters,
                    tableName = tableName,
                    operation = operation,
                    executionTimeMs = duration,
                    resultCount = resultCount
                )
                result
            } catch (e: Exception) {
                val duration = System.currentTimeMillis() - startTime
                AppLogger.logDatabaseError(
                    query = query,
                    parameters = parameters,
                    error = e,
                    tableName = tableName
                )
                AppLogger.logPerformance(
                    operation = "DB_ERROR:$operation",
                    durationMs = duration,
                    metadata = mapOf("table" to tableName, "query" to query)
                )
                throw e
            }
        }

        fun <T> logTransaction(
            transactionId: String = UUID.randomUUID().toString().take(8),
            operations: MutableList<String> = mutableListOf(),
            block: (MutableList<String>) -> T
        ): T {
            val startTime = System.currentTimeMillis()
            return try {
                val result = block(operations)
                val duration = System.currentTimeMillis() - startTime
                AppLogger.logDatabaseTransaction(
                    transactionId = transactionId,
                    operations = operations,
                    success = true,
                    executionTimeMs = duration
                )
                result
            } catch (e: Exception) {
                val duration = System.currentTimeMillis() - startTime
                AppLogger.logDatabaseTransaction(
                    transactionId = transactionId,
                    operations = operations,
                    success = false,
                    executionTimeMs = duration
                )
                AppLogger.logException("DatabaseTransaction", e, mapOf(
                    "transactionId" to transactionId,
                    "operationCount" to operations.size
                ))
                throw e
            }
        }
    }
}

// ============================================================
// Performance Tracker Helper
// ============================================================
class PerformanceTracker(private val operationName: String) {

    private val startTime = System.currentTimeMillis()
    private val checkpoints = mutableListOf<Pair<String, Long>>()

    fun checkpoint(name: String) {
        checkpoints.add(name to System.currentTimeMillis())
    }

    fun finish(metadata: Map<String, Any?> = emptyMap()) {
        val totalDuration = System.currentTimeMillis() - startTime

        val fullMetadata = metadata.toMutableMap()
        if (checkpoints.isNotEmpty()) {
            var previousTime = startTime
            checkpoints.forEachIndexed { index, (name, time) ->
                fullMetadata["checkpoint_${index}_${name}"] = "${time - previousTime}ms"
                previousTime = time
            }
        }

        AppLogger.logPerformance(
            operation = operationName,
            durationMs = totalDuration,
            metadata = fullMetadata
        )
    }
}

// ============================================================
// Network Client Factory with logging
// ============================================================
object LoggingNetworkClient {

    fun createOkHttpClient(): OkHttpClient {
        val httpLoggingInterceptor = HttpLoggingInterceptor { message ->
            Timber.v("OkHttp: $message")
        }.apply {
            level = HttpLoggingInterceptor.Level.BODY
        }

        return OkHttpClient.Builder()
            .addInterceptor(ComprehensiveLoggingInterceptor())
            .addInterceptor(httpLoggingInterceptor)
            .build()
    }
}

