        // Log logout
        AppLogger.logLogout(
            userId = "user_12345",
            reason = "session_expired"
        )
    }

    fun demonstrateDatabaseLogging() {
        // Simple query logging
        val results = DatabaseLogger.logQuery(
            query = "SELECT * FROM users WHERE age > ? AND status = ?",
            parameters = mapOf("age" to 18, "status" to "active"),
            tableName = "users",
            operation = "SELECT"
        ) {
            // Actual database query here
            listOf("user1", "user2", "user3")
        }

        // Transaction logging
        DatabaseLogger.logTransaction { operations ->
            operations.add("INSERT INTO orders (user_id, amount) VALUES (1, 99.99)")
            operations.add("UPDATE inventory SET quantity = quantity - 1 WHERE product_id = 42")
            operations.add("INSERT INTO audit_log (action, user_id) VALUES ('purchase', 1)")
            // Actual transaction operations
        }
    }

    fun demonstrateApiLogging() {
